import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import './StudentDashboard.css';

export default function StudentDashboard() {
  const [complaints, setComplaints] = useState([]);
  const [form, setForm] = useState({ category: '', description: '', priority: 'medium' });
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [debug, setDebug] = useState('');
  
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    console.log('Component mounted');
    console.log('Token:', token);
    console.log('User:', user);
    
    if (!token) {
      console.log('No token, redirecting to login');
      navigate('/login');
      return;
    }
    fetchComplaints();
  }, []);

  const fetchComplaints = async () => {
    console.log('Fetching complaints...');
    try {
      const res = await axios.get('/api/complaints/my', { 
        headers: { 'x-auth-token': token } 
      });
      console.log('Complaints fetched:', res.data);
      setComplaints(res.data);
    } catch (err) {
      console.error('Error fetching complaints:', err);
      if (err.response?.status === 401) {
        alert('Session expired. Please login again.');
        localStorage.clear();
        navigate('/login');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setDebug('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    console.log('=== FORM SUBMISSION START ===');
    console.log('Form data:', form);
    console.log('Token:', token);
    
    setSubmitting(true);
    setError('');
    setSuccess('');
    setDebug('');

    // Validate form
    if (!form.category) {
      setError('Please select a category');
      setSubmitting(false);
      return;
    }
    if (!form.description.trim()) {
      setError('Please enter a description');
      setSubmitting(false);
      return;
    }

    try {
      console.log('Making API request to /api/complaints');
      console.log('Request payload:', form);
      
      const response = await axios.post('/api/complaints', form, {
        headers: { 
          'x-auth-token': token,
          'Content-Type': 'application/json'
        }
      });
      
      console.log('✅ Success! Response:', response.data);
      setSuccess('✅ Complaint submitted successfully!');
      setDebug(`Success: Complaint ID ${response.data._id}`);
      setForm({ category: '', description: '', priority: 'medium' });
      fetchComplaints();
      
    } catch (err) {
      console.error('❌ ERROR DETAILS:');
      console.error('Error object:', err);
      console.error('Error response:', err.response);
      console.error('Error message:', err.message);
      
      if (err.code === 'ERR_NETWORK') {
        setError('❌ Cannot connect to server. Make sure backend is running on port 5000');
        setDebug('Network error - Check if backend is running');
      } else if (err.response) {
        // The request was made and the server responded with a status code
        console.error('Status:', err.response.status);
        console.error('Data:', err.response.data);
        
        if (err.response.status === 401) {
          setError('❌ Session expired. Please login again.');
          setDebug('Token expired - redirecting to login');
          setTimeout(() => {
            localStorage.clear();
            navigate('/login');
          }, 2000);
        } else if (err.response.status === 403) {
          setError('❌ Access denied. Student only.');
          setDebug('Role check failed - Are you logged in as student?');
        } else if (err.response.status === 400) {
          setError(`❌ ${err.response.data.message || 'Invalid data'}`);
          setDebug('Validation error - Check form fields');
        } else {
          setError(`❌ Server error (${err.response.status})`);
          setDebug(JSON.stringify(err.response.data));
        }
      } else if (err.request) {
        // The request was made but no response was received
        setError('❌ No response from server');
        setDebug('Request sent but no response - Check if backend is running');
      } else {
        // Something happened in setting up the request
        setError('❌ Request setup failed');
        setDebug(err.message);
      }
    } finally {
      setSubmitting(false);
      console.log('=== FORM SUBMISSION END ===');
    }
  };

  const logout = () => { 
    localStorage.clear(); 
    navigate('/login'); 
  };

  const formatDate = d => new Date(d).toLocaleDateString();

  if (loading) {
    return <div className="loading">Loading...</div>;
  }

  return (
    <div className="student-container">
      <nav className="student-nav">
        <div className="nav-content">
          <div className="nav-brand">
            <h1>Hostel<span>Hub</span></h1>
            <p>Student Dashboard</p>
          </div>
          <div className="nav-user">
            <span>{user?.name} ({user?.email})</span>
            <button onClick={logout} className="logout-btn">Logout</button>
          </div>
        </div>
      </nav>

      <div className="student-content">
        <div className="complaint-form-section">
          <h2>Submit New Complaint</h2>
          
          {/* Debug Info - Remove after fixing */}
          {debug && (
            <div style={{
              background: '#e7f5ff',
              border: '2px solid #339af0',
              padding: '10px',
              marginBottom: '20px',
              borderRadius: '8px',
              fontFamily: 'monospace',
              fontSize: '12px'
            }}>
              <strong>🔧 Debug Info:</strong>
              <pre>{debug}</pre>
            </div>
          )}
          
          {error && <div className="error-message">{error}</div>}
          {success && <div className="success-message">{success}</div>}

          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Category *</label>
              <select 
                name="category" 
                value={form.category} 
                onChange={handleChange}
                required
              >
                <option value="">Select a category</option>
                <option value="plumbing">Plumbing</option>
                <option value="electrical">Electrical</option>
                <option value="carpentry">Carpentry</option>
                <option value="cleaning">Cleaning</option>
                <option value="other">Other</option>
              </select>
            </div>

            <div className="form-group">
              <label>Description *</label>
              <textarea
                name="description"
                value={form.description}
                onChange={handleChange}
                placeholder="Describe the issue in detail..."
                rows="4"
                required
              />
            </div>

            <div className="form-group">
              <label>Priority</label>
              <select name="priority" value={form.priority} onChange={handleChange}>
                <option value="low">Low</option>
                <option value="medium">Medium</option>
                <option value="high">High</option>
              </select>
            </div>

            <button 
              type="submit" 
              className="submit-btn" 
              disabled={submitting}
            >
              {submitting ? 'Submitting...' : 'Submit Complaint'}
            </button>
          </form>
        </div>

        <div className="complaints-list-section">
          <h2>My Complaints</h2>
          {complaints.length === 0 ? (
            <p>No complaints yet</p>
          ) : (
            complaints.map(c => (
              <div key={c._id} className="complaint-card">
                <h3>{c.category}</h3>
                <p>{c.description}</p>
                <div className="complaint-footer">
                  <span>Priority: {c.priority}</span>
                  <span>Status: {c.status}</span>
                  <span>{formatDate(c.createdAt)}</span>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}
